import{_ as o,C as n,o as l,c as s,E as i,w as e,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to Romania","description":"Immigration pathways and relocation guide for Romania","frontmatter":{"layout":"doc","title":"Moving to Romania","description":"Immigration pathways and relocation guide for Romania"},"headers":[],"relativePath":"europe/romania/moving-there.md","filePath":"europe/romania/moving-there.md","lastUpdated":null}'),m={name:"europe/romania/moving-there.md"};function h(g,t,u,c,f,b){const a=n("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:e(()=>[...t[0]||(t[0]=[r("EU: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:e(()=>[...t[1]||(t[1]=[r("Non-EU: Work Visa",-1)])]),_:1}),i(a,{variant:"green"},{default:e(()=>[...t[2]||(t[2]=[r("Digital Nomad Visa Available",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-romania" tabindex="-1">Moving to Romania <a class="header-anchor" href="#moving-to-romania" aria-label="Permalink to &quot;Moving to Romania&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register with the General Inspectorate for Immigration (IGI)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>Residence card</strong>: Issued for stays over 3 months</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Romanian employer)</li><li>Student visa (enrollment at Romanian university)</li><li>Family reunification</li><li>Digital Nomad Visa</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Romanian employer</td><td>Up to 1 year, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Romanian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€35,000+/year)</td><td>Up to 2 years</td></tr><tr><td>Digital Nomad Visa</td><td>Remote work, income threshold</td><td>Up to 1 year, renewable</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Romania offers a <strong>dedicated digital nomad visa</strong> (since 2021):</p><ul><li>Valid for up to <strong>1 year</strong>, renewable</li><li>Requirements: <ul><li>Remote work for a company outside Romania</li><li>Monthly income of at least €3,300 (3x gross average salary)</li><li>Valid health insurance</li><li>Clean criminal record</li></ul></li><li>Can bring family members</li><li>Cannot work for Romanian employers</li><li>Good option for testing living in Romania before committing</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance (non-EU)</li><li>[ ] <strong>Healthcare</strong>: Private health insurance initially; register with CNAS after residency</li><li>[ ] <strong>HRT</strong>: Get 6-month supply and doctor&#39;s letter (translated to Romanian)</li><li>[ ] <strong>Banking</strong>: Consider BCR, BRD, ING, or Revolut</li><li>[ ] <strong>Housing</strong>: Research rental market (imobiliare.ro, olx.ro)</li><li>[ ] <strong>Language</strong>: Basic Romanian helpful; moderate English in cities</li><li>[ ] <strong>Document translation</strong>: Official Romanian translations needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with IGI (non-EU) or municipality (EU)</li><li>[ ] Obtain Romanian CNP (personal numeric code) — essential for all services</li><li>[ ] Register with CNAS (National Health Insurance House)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Orange, Vodafone, Digi)</li><li>[ ] Connect with LGBTQ+ community (ACCEPT)</li><li>[ ] Register with Institutul de Endocrinologie for trans healthcare</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Low</strong> — one of the most affordable EU countries</li><li>Monthly rent (1-bed): €300-600 (Bucharest), €250-450 (Cluj-Napoca), €200-400 (Timișoara), €200-350 (Iași)</li><li>Monthly groceries: €200-300</li><li>Public transport: €15-25/month (Bucharest)</li><li>Dining out: €6-12 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Bucharest</strong></td><td>Active, growing scene</td><td>Only comprehensive option</td></tr><tr><td><strong>Cluj-Napoca</strong></td><td>Moderate scene</td><td>Limited</td></tr><tr><td><strong>Timișoara</strong></td><td>Small scene</td><td>None</td></tr><tr><td><strong>Iași</strong></td><td>Very limited</td><td>None</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to 5°C), snow common</li><li><strong>Summers</strong>: Warm to hot (25-35°C)</li><li><strong>Spring/Autumn</strong>: Mild and pleasant</li><li><strong>Best time to arrive</strong>: Spring or early autumn</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Romanian (Romance language, closest to Italian)</li><li>English: Moderate in Bucharest and Cluj, limited elsewhere</li><li>French: Somewhat understood by older generations</li><li>Romanian is a Romance language and relatively accessible for English/French/Italian speakers</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://igi.mai.gov.ro/" target="_blank" rel="noreferrer">IGI (General Inspectorate for Immigration)</a></li><li><a href="https://www.cnas.ro/" target="_blank" rel="noreferrer">CNAS (National Health Insurance House)</a></li><li><a href="https://igi.mai.gov.ro/digital-nomad/" target="_blank" rel="noreferrer">Romanian Digital Nomad Visa Information</a></li><li><a href="https://acceptromania.ro/" target="_blank" rel="noreferrer">ACCEPT (LGBTQ+ Organization)</a></li><li><a href="https://www.imobiliare.ro/" target="_blank" rel="noreferrer">Imobiliare.ro (housing)</a></li></ul>',27))])}const v=o(m,[["render",h]]);export{y as __pageData,v as default};
